/** UsptJobCareerDao.update */
update uspt_job_career
set
	wrkplc			= #{wrkplc}
	, bgnde			= #{bgnde}
	, endde			= #{endde}
	, job			= #{job}
	, retire_resn	= #{retireResn}
	, updater_id	= #{updaterId}
	, updated_dt	= #{updatedDt}
